CREATE INDEX benchmark_logs_partitioned_idx ON benchmark_logs_partitioned USING bm25 (id, message, country, severity, timestamp, metadata) WITH (key_field = 'id', text_fields = '{"country": {"fast": true, "tokenizer": {"type": "raw", "lowercase": true} }}', json_fields = '{"metadata": { "fast": true, "tokenizer": {"type": "raw", "lowercase": true}}}', datetime_fields = '{"timestamp": {"fast": true}}');
